    13→type TransflowStep struct {
    14→	Type    string   `yaml:"type"`
    15→	ID      string   `yaml:"id"`
    16→	Engine  string   `yaml:"engine"`
    17→	Recipes []string `yaml:"recipes"`
    18→}
    19→
    20→type TransflowConfig struct {
    21→	Version      string          `yaml:"version"`
    22→	ID           string          `yaml:"id"`
    23→	TargetRepo   string          `yaml:"target_repo"`
    24→	TargetBranch string          `yaml:"target_branch"`
    25→	BaseRef      string          `yaml:"base_ref"`
    26→	Lane         string          `yaml:"lane"`
    27→	BuildTimeout string          `yaml:"build_timeout"`
    28→	Steps        []TransflowStep `yaml:"steps"`
    29→	SelfHeal     *SelfHealConfig `yaml:"self_heal"`
    30→}
    31→
    32→func LoadConfig(path string) (*TransflowConfig, error) {
    33→	b, err := ioutil.ReadFile(path)
    34→	if err != nil {
    35→		return nil, err
    36→	}
    37→	var cfg TransflowConfig
    38→	if err := yaml.Unmarshal(b, &cfg); err != nil {
    39→		return nil, err
    40→	}
    41→
    42→	// Set default self-heal config if not provided or apply defaults to existing config
    43→	if cfg.SelfHeal == nil {
    44→		cfg.SelfHeal = GetDefaultSelfHealConfig()
    45→	} else {
    46→		// Apply defaults for missing fields
    47→		if cfg.SelfHeal.MaxRetries == 0 {
    48→			cfg.SelfHeal.MaxRetries = GetDefaultSelfHealConfig().MaxRetries
    49→		}
    50→		// Cooldown defaults to empty string, so no need to set it
    51→		// For enabled field, explicit false should remain false, no default needed
    52→	}
    53→
    54→	if err := cfg.Validate(); err != nil {
    55→		return nil, err
    56→	}
    57→
    58→	return &cfg, nil
    59→}
    60→
    61→func (c *TransflowConfig) Validate() error {
    62→	if c.ID == "" {
    63→		return errors.New("id is required")
    64→	}
    65→	if c.TargetRepo == "" {
    66→		return errors.New("target_repo is required")
    67→	}
    68→	if c.BaseRef == "" {
    69→		return errors.New("base_ref is required")
    70→	}
    71→	if len(c.Steps) == 0 {
    72→		return errors.New("at least one step is required")
    73→	}
    74→
    75→	// Validate self-heal configuration if provided
    76→	if c.SelfHeal != nil {
    77→		if err := c.SelfHeal.Validate(); err != nil {
    78→			return fmt.Errorf("invalid self_heal config: %w", err)
    79→		}
    80→	}
    81→
    82→	// Validate build timeout if provided
    83→	if c.BuildTimeout != "" {
    84→		if _, err := c.ParseBuildTimeout(); err != nil {
    85→			return fmt.Errorf("invalid build_timeout: %w", err)
    86→		}
    87→	}
    88→
    89→	return nil
    90→}
    91→
    92→func (c *TransflowConfig) ParseBuildTimeout() (time.Duration, error) {
    93→	if c.BuildTimeout == "" {
    94→		return 10 * time.Minute, nil // default
    95→	}
    96→
    97→	duration, err := time.ParseDuration(c.BuildTimeout)
    98→	if err != nil {
    99→		return 0, fmt.Errorf("invalid build timeout format: %v", err)
   100→	}
   101→
   102→	if duration < 0 {
   103→		return 0, errors.New("build timeout cannot be negative")
   104→	}
   105→
   106→	return duration, nil
   107→}
